    if order.status in ["completed", "cancelled"]:
        raise HTTPException(status_code=400, detail="Cannot cancel this order")

    if order.status == "in_progress":
        raise HTTPException(status_code=400, detail="Cannot cancel during trip")

    cancel_fee = 0.0
    if order.status == "assigned":
        cancel_fee = 5.0

    order.status = "cancelled"
    order.cancel_reason = cancel.reason
    order.cancel_fee = cancel_fee
    order.completed_at = datetime.utcnow()

    if order.driver:
        order.driver.status = "online"

    db.commit()

    return {"message": "Order cancelled", "cancel_fee": cancel_fee}


