from fastapi import FastAPI, Depends, HTTPException, WebSocket, Header
from fastapi.middleware.cors import CORSMiddleware
from sqlalchemy.orm import Session
from pydantic import BaseModel
from typing import Optional
from datetime import datetime, timedelta
import math
import json
import os

from database import get_db, User, Driver, Order, Rating, AuditLog, AIConversation, Base, engine
from passlib.context import CryptContext
from jose import JWTError, jwt

app = FastAPI(title="AI Ride Platform API", version="1.0.0")

app.add_middleware(
    CORSMiddleware,
    allow_origins=["*"],
    allow_credentials=True,
    allow_methods=["*"],
    allow_headers=["*"],
)

pwd_context = CryptContext(schemes=["bcrypt"], deprecated="auto")
SECRET_KEY = os.getenv("SECRET_KEY", "your-secret-key-change-in-production")
ALGORITHM = "HS256"
ACCESS_TOKEN_EXPIRE_MINUTES = 1440
AI_MOCK = os.getenv("AI_MOCK", "true").lower() == "true"

Base.metadata.create_all(bind=engine)


def verify_token(token: str):
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=[ALGORITHM])
        return payload
    except JWTError:
        return None


def get_current_user(authorization: str = Header(None), db: Session = Depends(get_db)):
    if not authorization:
        raise HTTPException(status_code=401, detail="Not authenticated")
    token = authorization.replace("Bearer ", "")
    payload = verify_token(token)
    if not payload:
        raise HTTPException(status_code=401, detail="Invalid token")
    user = db.query(User).filter(User.id == payload.get("user_id")).first()
    if not user:
        raise HTTPException(status_code=401, detail="User not found")
    return user


def create_access_token(data: dict):
    to_encode = data.copy()
    expire = datetime.utcnow() + timedelta(minutes=ACCESS_TOKEN_EXPIRE_MINUTES)
    to_encode.update({"exp": expire})
    return jwt.encode(to_encode, SECRET_KEY, algorithm=ALGORITHM)


def calculate_distance(x1, y1, x2, y2):
    return math.sqrt((x2 - x1) ** 2 + (y2 - y1) ** 2)


def calculate_base_price(distance):
    base = 8.0
    per_km = 2.5
    return round(base + distance * per_km, 2)


def get_supply_demand_multiplier(db: Session):
    if AI_MOCK:
        return 1.0
    now = datetime.utcnow()
    last_hour = now - timedelta(hours=1)
    active_orders = db.query(Order).filter(
        Order.status.in_(["matching", "assigned", "in_progress"]),
        Order.created_at >= last_hour
    ).count()
    active_drivers = db.query(Driver).filter(Driver.status == "online").count()
    avg_orders = 10.0
    avg_drivers = 20.0
    demand_factor = active_orders / avg_orders if avg_orders > 0 else 1.0
    supply_factor = active_drivers / avg_drivers if avg_drivers > 0 else 1.0
    if supply_factor == 0:
        return 1.5
    ratio = demand_factor / supply_factor
    if ratio > 1.5:
        return min(1.0 + (ratio - 1.0) * 0.3, 1.5)
    elif ratio < 0.7:
        return max(1.0 - (0.7 - ratio) * 0.2, 0.8)
    return 1.0


def calculate_driver_score(driver: Driver, distance: float):
    distance_weight, rating_weight, rejection_weight = 0.4, 0.3, 0.3
    max_distance = 20.0
    distance_score = max(0, 1 - (distance / max_distance))
    rating_score = driver.user.rating / 5.0 if driver.user.rating else 0.5
    rejection_score = 1 - driver.rejection_rate
    return round(distance_score * distance_weight + rating_score * rating_weight + rejection_score * rejection_weight, 3)


def log_audit(db: Session, operator_id: int, action: str, target_type: str, target_id: int, details: dict):
    log = AuditLog(operator_id=operator_id, action=action, target_type=target_type, target_id=target_id, details=json.dumps(details))
    db.add(log)
    db.commit()


