        "dest_address": order.dest_address, "status": order.status,
        "base_price": order.base_price, "dynamic_multiplier": order.dynamic_multiplier,
        "final_price": order.final_price, "distance": order.distance, "estimated_wait": order.estimated_wait,
        "cancel_fee": order.cancel_fee, "created_at": order.created_at.isoformat(),
        "assigned_at": order.assigned_at.isoformat() if order.assigned_at else None,
