@app.post("/api/passenger/orders/{order_id}/cancel")
def cancel_order(order_id: int, cancel: OrderCancel, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    order = db.query(Order).filter(Order.id == order_id).first()
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    if order.passenger_id != current_user.id:
        raise HTTPException(status_code=403, detail="Access denied")
    if order.status in ["completed", "cancelled"]:
        raise HTTPException(status_code=400, detail="Cannot cancel this order")
    if order.status == "in_progress":
        raise HTTPException(status_code=400, detail="Cannot cancel during trip")
    cancel_fee = 5.0 if order.status == "assigned" else 0.0
    order.status = "cancelled"
    order.cancel_reason = cancel.reason
    order.cancel_fee = cancel_fee
    order.completed_at = datetime.utcnow()
    if order.driver:
        order.driver.status = "online"
    db.commit()
    return {"message": "Order cancelled", "cancel_fee": cancel_fee}


@app.post("/api/passenger/orders/{order_id}/rate")
def rate_driver(order_id: int, rating: RatingCreate, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    order = db.query(Order).filter(Order.id == order_id).first()
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    if order.passenger_id != current_user.id:
        raise HTTPException(status_code=403, detail="Access denied")
    if order.status != "completed":
        raise HTTPException(status_code=400, detail="Can only rate completed orders")
    existing = db.query(Rating).filter(Rating.order_id == order_id, Rating.from_user_id == current_user.id).first()
    if existing:
        raise HTTPException(status_code=400, detail="Already rated")
    new_rating = Rating(order_id=order_id, from_user_id=current_user.id, to_user_id=order.driver.user_id,
                        score=rating.score, comment=rating.comment)
    db.add(new_rating)
    driver = order.driver
    all_ratings = db.query(Rating).filter(Rating.to_user_id == driver.user_id).all()
    total_score = sum(r.score for r in all_ratings) + rating.score
    driver.user.rating = round(total_score / (len(all_ratings) + 1), 1)
    db.commit()
    return {"message": "Rating submitted"}


